const MANUAL_SMA = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, plot, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Manual SMA",
    apiVersion: 1,
    overlay: true,
    compute({ bar, ta, plot }) {
        // An SMA is just the mean of the last N closes. chartlang ships a
        // built-in \`ta.sma\`, but you can also spell the formula out by hand
        // straight from the price series.
        //
        // \`bar.close\` is a price series: \`bar.close[0]\` is the current close,
        // \`bar.close[1]\` is one bar ago, and so on. Index it directly — no
        // helper needed. (It still works as a plain number too, so
        // \`bar.close * 2\` and \`ta.sma(bar.close, 5)\` are fine.)
        //
        // Mean of the last 5 closes. \`bar.close\` is a price series, so a
        // bounded \`for\` loop indexes the window directly: chartlang resolves
        // \`bar.close[i]\` over the literal loop bounds, so the buffer is sized
        // to exactly 5 slots (maxLookback 4) with no dynamic-index warning —
        // identical to spelling out \`(bar.close[0] + ... + bar.close[4]) / 5\`.
        // Out-of-range reads are NaN, so this warms up over 4 bars,
        // bar-for-bar identical to ta.sma(close, 5).
        let sum = 0;
        for (let i = 0; i < 5; i++) {
            sum += bar.close[i];
        }
        const manual = sum / 5;

        // Plot the built-in red ta.sma(5) first, then the green manual line
        // last so it renders on top — they coincide bar-for-bar after warmup,
        // so the green manual SMA sits over the red automatic one.
        plot(ta.sma(bar.close, 5), { color: "#ef5350", title: "ta.sma(5)" });
        plot(manual, { color: "#26a69a", title: "Manual SMA(5)" });
    },
});
`;

const TREND_COMPOSITION = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, input, plot, ta } from "@invinite-org/chartlang-core";

// Private dep — bound to a local \`const\`, never exported. Mounted as a
// data feed only; its own plots are dropped by the runtime filter.
// Tip: prefix this with \`export\` (\`export const baseTrend = ...\`) to also
// plot its line — exported indicators render; private ones stay data-only.
const baseTrend = defineIndicator({
    name: "Base Trend",
    apiVersion: 1,
    overlay: true,
    inputs: { length: input.int(20, { min: 2, max: 250 }) },
    compute({ bar, ta, inputs, plot }) {
        plot(ta.ema(bar.close, inputs.length as number), { title: "line" });
    },
});

// Drawn sibling — named export. Renders under the \`export:slowTrend/\`
// slot-id prefix, separate from the default export's slots.
export const slowTrend = defineIndicator({
    name: "Slow Trend",
    apiVersion: 1,
    overlay: true,
    compute({ bar, ta, plot }) {
        plot(ta.ema(bar.close, 50), { color: "#9ca3af", title: "line" });
    },
});

// Drawn primary — default export. Consumes both deps and marks crossovers.
export default defineIndicator({
    name: "Trend Composition",
    apiVersion: 1,
    overlay: true,
    compute({ bar, ta, plot }) {
        const fast = baseTrend.output("line");
        const slow = slowTrend.output("line");
        if (ta.crossover(fast, slow).current) {
            plot(bar.low, {
                color: "#22c55e",
                title: "Cross",
                style: { kind: "shape", shape: "triangle-up", size: 10, location: "below" },
            });
        }
    },
});
`;

const HTF_TREND_FILTER = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, plot, request, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "HTF Trend Filter",
    apiVersion: 1,
    overlay: true,
    compute({ bar, ta, plot, request }) {
        // Current-timeframe trend.
        const fast = ta.ema(bar.close, 20);
        plot(fast, { color: "#26a69a", title: "EMA(20)" });

        // Weekly trend computed ON the weekly bars (20 weekly EMA), aligned
        // no-lookahead to the chart. The callback runs on the higher-timeframe
        // clock, so this is a true weekly EMA(20) (~140 days), not 20 main
        // bars of a weekly-stepped series.
        const weeklyTrend = request.security({ interval: "1W" }, (bar) => ta.ema(bar.close, 20));
        plot(weeklyTrend, { color: "#ef5350", title: "Weekly EMA(20)" });
    },
});
`;

const LTF_FILTER = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, plot, request, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "LTF Filter",
    apiVersion: 1,
    overlay: false,
    compute({ bar, ta, plot, request }) {
        // Current-timeframe RSI(14).
        const rsi = ta.rsi(bar.close, 14);
        plot(rsi, { color: "#26a69a", title: "RSI(14)" });

        // Hourly RSI(14) computed ON the 1h bars — a LOWER (finer) timeframe
        // than a daily chart — aligned no-lookahead to the chart. On each daily
        // bar this reads the value of the LAST 1h bar that closed at/before the
        // daily bar's close (the most recent sub-bar), non-repainting — the
        // finer mirror of \`htf-trend-filter.chart.ts\`'s forward-aligned HTF
        // trend. The callback runs on the hourly clock, so this is a true
        // hourly RSI(14), sampled once per daily bar.
        const hourlyRsi = request.security({ interval: "1h" }, (bar) => ta.rsi(bar.close, 14));
        plot(hourlyRsi, { color: "#ef5350", title: "Hourly RSI(14)" });
    },
});
`;

const SMA_OFFSET = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, plot, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "SMA Offset",
    apiVersion: 1,
    overlay: true,
    compute({ bar, ta, plot }) {
        const sma = ta.sma(bar.close, 20);
        plot(sma, { color: "#26a69a", title: "SMA(20)" });

        // The universal \`opts.offset\` is a presentation display shift, not a
        // value-read: a positive offset renders the line to the right
        // (future) and a negative offset to the left (past), while the
        // numeric series value stays unshifted (alerts and indexing see the
        // value computed at the current bar). The shift lives on the \`ta\`
        // call, since \`plot\` has no offset option.
        plot(ta.sma(bar.close, 20, { offset: 5 }), { color: "#ef5350", title: "SMA(20) +5" });
        plot(ta.sma(bar.close, 20, { offset: -5 }), { color: "#42a5f5", title: "SMA(20) −5" });
    },
});
`;

const PIVOT_HIGH_RAY = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, draw, state, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Pivot High Ray",
    apiVersion: 1,
    overlay: true,
    // One ray, reused across every bar (see below), so a single "lines"
    // slot is the whole drawing budget we need.
    maxDrawings: { lines: 1, labels: 0, boxes: 0, polylines: 0, other: 0 },
    compute({ bar, ta, state, draw }) {
        // Swing-high detection: a bar whose high tops the 5 bars on each
        // side. A pivot can only be *confirmed* once the 5 bars to its
        // right exist, so \`pivots.high.current\` turns non-NaN 5 bars late
        // and reports the high from 5 bars back.
        const pivots = ta.pivotsHighLow({ leftLength: 5, rightLength: 5 });

        // \`state.*\` slots persist across bars (Pine \`var\`). Remember the
        // latest pivot high's price AND time so we can keep drawing from
        // it on every later bar — this is the "track the last high" part.
        const lastTime = state.float(Number.NaN);
        const lastPrice = state.float(Number.NaN);

        if (!Number.isNaN(pivots.high.current)) {
            // The confirmed pivot sits 5 bars back. \`bar.point(-5, …)\`
            // resolves that offset to the real historical timestamp from
            // the runtime's time buffer — no hand-rolled time series. The
            // offset literal must stay in sync with \`rightLength\` above (a
            // negative integer literal is what sizes the lookback buffer).
            const anchor = bar.point(-5, pivots.high.current);
            lastTime.value = anchor.time;
            lastPrice.value = anchor.price;
        }

        // Once a high is known, draw a horizontal ray from it to the right
        // edge. Calling \`draw.horizontalRay\` every bar from this same line
        // of source reuses one drawing handle — the runtime emits an
        // \`update\`, not a new ray — so the single line simply jumps to each
        // new swing high as it is confirmed.
        if (!Number.isNaN(lastPrice.value)) {
            draw.horizontalRay(
                { time: lastTime.value, price: lastPrice.value },
                { color: "#ef5350", lineWidth: 2, lineStyle: "dashed" },
            );
        }
    },
});
`;

const FORECAST_LINE = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, draw, plot, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Forecast Line",
    apiVersion: 1,
    overlay: true,
    // One projected line, redrawn every bar from the same source line, so a
    // single "lines" slot is the whole drawing budget we need.
    maxDrawings: { lines: 1, labels: 0, boxes: 0, polylines: 0, other: 0 },
    compute({ bar, ta, draw, plot }) {
        // A 20-bar EMA, kept as an indexable series so we can read its value
        // now (\`trend[0]\`) and \`LOOKBACK\` bars ago (\`trend[LOOKBACK]\`).
        const LOOKBACK = 20;
        const PROJECT = 20;
        const trend = ta.ema(bar.close, LOOKBACK);
        plot(trend, { color: "#26a69a", title: "EMA(20)" });

        // Per-bar slope of the recent trend, in price units per bar.
        const slope = (trend[0] - trend[LOOKBACK]) / LOOKBACK;

        // Project that slope \`PROJECT\` bars into the future. \`bar.point(0, …)\`
        // anchors the line's start at the current bar; \`bar.point(+PROJECT, …)\`
        // resolves the FORWARD offset to an extrapolated future timestamp
        // (\`lastTime + PROJECT * spacing\`, spacing = median retained-bar delta).
        // A positive offset is what makes the line reach to the RIGHT of the
        // last candle — the negative/zero offsets are covered by pivot-high-ray.
        if (Number.isFinite(slope)) {
            const start = bar.point(0, trend[0]);
            const end = bar.point(PROJECT, trend[0] + slope * PROJECT);
            draw.line(start, end, { color: "#ab47bc", lineWidth: 2, lineStyle: "dotted" });
        }
    },
});
`;

const FILL_BETWEEN_BAND = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { type WorldPoint, defineIndicator, draw, plot, ta } from "@invinite-org/chartlang-core";

// Two persistent edge arrays, accumulated one \`{ time, price }\` vertex per
// bar. They live at module scope (not \`state.*\`) because they are the
// drawing's geometry, re-snapshotted into one \`draw.fillBetween\` callsite
// every bar — the same per-bar-re-emit idiom the ray/line examples use.
const fastEdge: WorldPoint[] = [];
const slowEdge: WorldPoint[] = [];

export default defineIndicator({
    name: "Fill Between Band",
    apiVersion: 1,
    overlay: true,
    // One ribbon, re-emitted every bar from the same source line, so a single
    // "polylines" slot (fill-between's bucket) is the whole drawing budget.
    maxDrawings: { lines: 0, labels: 0, boxes: 0, polylines: 1, other: 0 },
    compute({ bar, ta, plot, draw }) {
        const fast = ta.ema(bar.close, 12);
        const slow = ta.ema(bar.close, 26);

        // Plot the two EMAs so the band's edges are visible on the candles.
        plot(fast, { color: "#3b82f6", title: "EMA(12)" });
        plot(slow, { color: "#9ca3af", title: "EMA(26)" });

        // Grow both edges by one vertex per bar. The fill is the closed
        // polygon \`fastEdge\` forward then \`slowEdge\` reversed, so the two
        // running EMAs become the top and bottom of a filled ribbon.
        if (Number.isFinite(fast.current) && Number.isFinite(slow.current)) {
            fastEdge.push({ time: bar.time, price: fast.current });
            slowEdge.push({ time: bar.time, price: slow.current });
        }

        // Re-emit the band from this same source line every bar. The runtime
        // keys the callsite by its injected slot id and merges each
        // re-emission into one persistent drawing, so the ribbon simply
        // extends to the new bar rather than stacking a fresh fill each step.
        if (fastEdge.length >= 2) {
            draw.fillBetween(fastEdge, slowEdge, {
                fill: "#3b82f6",
                fillAlpha: 0.2,
                color: "#3b82f6",
                lineWidth: 1,
            });
        }
    },
});
`;

const ANCHORED_LINE = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, draw, state } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Anchored Line",
    apiVersion: 1,
    overlay: true,
    // One line, redrawn every bar from the same source line, so a single
    // "lines" slot is the whole drawing budget we need.
    maxDrawings: { lines: 1, labels: 0, boxes: 0, polylines: 0, other: 0 },
    compute({ bar, state, draw }) {
        // Pin the START anchor at an ABSOLUTE point in time: the first bar's
        // own timestamp and close, captured once into persistent \`state.*\`
        // slots (Pine \`var\`). \`NaN\` is the "not captured yet" sentinel, so the
        // very first bar — and only that bar — fills the slots. From then on
        // the start anchor is a fixed \`{ time, price }\` that never moves.
        const startTime = state.float(Number.NaN);
        const startPrice = state.float(Number.NaN);
        if (Number.isNaN(startTime.value)) {
            startTime.value = bar.time;
            // \`bar.close\` is a Series VIEW object, not a number — index it
            // (\`[0]\`) to pin the first bar's close as a finite scalar. Storing
            // the view directly would persist a live proxy whose value tracks
            // the head, and the drawing's price anchor would fail the runtime's
            // finite-WorldPoint check (dropped as a malformed emission).
            startPrice.value = bar.close[0];
        }

        // Draw a line from that absolute-time start to a BAR-INDEX end. The two
        // anchor styles compose because both resolve to a \`WorldPoint\`:
        //   • start — a literal \`{ time, price }\` built from the remembered
        //     absolute timestamp (the "start at X point in time" case).
        //   • end   — \`bar.point(0, …)\`, the offset-anchored current bar (the
        //     "start at X bar index" case; offset 0 == the live bar's time).
        // Re-emitting from this same source line every bar reuses one drawing
        // handle, so the line's tail tracks the latest bar while its head stays
        // pinned to the first bar's time.
        draw.line({ time: startTime.value, price: startPrice.value }, bar.point(0, bar.close), {
            color: "#3b82f6",
            lineWidth: 2,
        });
    },
});
`;

const UP_STREAK = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, plot, state } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Up Streak",
    apiVersion: 1,
    overlay: false,
    compute({ bar, state, plot }) {
        // Consecutive up-closes. This is the case that genuinely NEEDS a
        // writable series: the value is SELF-REFERENTIAL — it is defined in
        // terms of its OWN value one bar ago — so it cannot be read off
        // \`bar.close[N]\` the way a plain price lookback can (that is the
        // \`directly-indexable-bar-series\` / Manual SMA case). \`state.series\`
        // both STORES this bar's streak and lets us look it back N bars later.
        const streak = state.series(0);
        const up = bar.close.current > bar.close[1];

        // \`streak[1]\` is the committed streak one bar ago. On the very first
        // bar it is NaN (no committed history yet), so the warmup guard treats
        // it as 0 before incrementing; a down-close resets the streak to 0.
        streak.value = up ? (Number.isFinite(streak[1]) ? streak[1] : 0) + 1 : 0;

        plot(streak.current, { title: "Up streak" });
        // The history index proves the writable series is also indexable: this
        // is the streak as it stood three bars ago (NaN during warmup).
        plot(streak[3], { title: "Streak 3 bars ago" });
    },
});
`;

const ROLLING_WINDOW_MEAN = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, plot, state } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Rolling Window Mean",
    apiVersion: 1,
    overlay: true,
    compute({ bar, state, plot }) {
        // A bounded bag of the last 20 closes. This is the case that genuinely
        // needs a PUSHED collection, not a single \`state.series\`: we push one
        // value per bar into a fixed-capacity FIFO ring (oldest evicted at
        // capacity) and then iterate the ELEMENTS to average them. \`state.array\`
        // is "a bounded bag of the last K things I pushed"; \`state.series\` is
        // "one value's bar history" — neither expresses the other.
        const win = state.array<number>(20);
        win.push(bar.close.current);

        // \`get(i)\` walks the ELEMENTS (0 = newest), not bars. The loop bound is
        // a literal and the inner \`if (i < win.size)\` guard skips the unfilled
        // slots during warmup — \`push\`/\`get\` are handle methods, so they are
        // legal inside the bounded loop (only the allocation call is not).
        let sum = 0;
        for (let i = 0; i < 20; i++) {
            if (i < win.size) sum += win.get(i);
        }

        plot(win.size > 0 ? sum / win.size : Number.NaN, { title: "Mean(20)" });
    },
});
`;

const VOLUME_BY_LEVEL = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, plot, state } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Volume by Level",
    apiVersion: 1,
    overlay: true,
    compute({ bar, state, plot }) {
        // A keyed accumulator: bucket each bar's volume under its rounded close
        // price. This is the case that genuinely needs a KEY→VALUE store, not a
        // FIFO of pushed values: many bars revisit the same price level, so we
        // read-modify-write one entry per level. \`get\` returns \`undefined\` for a
        // never-seen level (distinct from a real 0), so \`?? 0\` seeds it; a new
        // level once 64 are tracked evicts the oldest-inserted one (bounded so it
        // serializes).
        const levels = state.map<number, number>(64);
        const key = Math.round(bar.close.current);
        levels.set(key, (levels.get(key) ?? 0) + bar.volume.current);

        // Mark the current point of control: the price level holding the most
        // accumulated volume so far. v1 iterates with \`keyAt(i)\` + \`size\`, not an
        // iterator — the loop bound is the literal capacity and the inner
        // \`if (i < levels.size)\` guard skips the unfilled slots, the same bounded
        // shape \`state.array\` uses (\`keyAt\`/\`get\` are handle methods, so they are
        // legal inside the bounded loop; only the allocation call is not).
        let pocLevel = Number.NaN;
        let pocVolume = -1;
        for (let i = 0; i < 64; i++) {
            if (i < levels.size) {
                const level = levels.keyAt(i);
                if (level !== undefined) {
                    const volume = levels.get(level) ?? 0;
                    if (volume > pocVolume) {
                        pocVolume = volume;
                        pocLevel = level;
                    }
                }
            }
        }

        plot(pocLevel, { color: "#ab47bc", title: "Volume POC" });
    },
});
`;

const ROLLING_ZSCORE = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { array, defineIndicator, plot, state } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Rolling Z-Score",
    apiVersion: 1,
    overlay: false,
    compute({ bar, state, plot }) {
        // Push one close per bar into a bounded FIFO window, then reduce over the
        // window with the analytic methods on the handle. A z-score is the
        // canonical "how far is now from the recent norm" — \`(x − mean) / stdev\`.
        const win = state.array<number>(20);
        win.push(bar.close.current);

        // Two call styles, one implementation: \`win.avg()\` is the method and
        // \`array.stdev(win)\` is the Pine-parity free-function alias that delegates
        // 1:1 to \`win.stdev()\` — they can never drift. Both skip NaN and return
        // NaN on an empty window, so guard the divide while the window warms.
        const mean = win.avg();
        const sd = array.stdev(win);
        plot(sd > 0 ? (bar.close.current - mean) / sd : 0, { title: "Z-Score(20)" });
    },
});
`;

const SYMBOL_RATIO = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, plot, request } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Symbol Ratio",
    apiVersion: 1,
    // A price ratio (~0.35) is orders of magnitude below the chart's price
    // scale, so it must render in its OWN sub-pane — on the price overlay it
    // collapses to a flat line at the axis floor. \`overlay: false\` gives the
    // ratio its own y-scale.
    overlay: false,
    compute({ plot, request }) {
        // Read two DIFFERENT instruments at the chart interval via the
        // multi-symbol \`request.security({ symbol, interval })\` form. \`symbol\`
        // must be a compile-time literal, and a non-chart symbol requires the
        // adapter's \`multiSymbol\` capability — otherwise each series degrades
        // to all-NaN with one \`multi-symbol-not-supported\` diagnostic.
        const spy = request.security({ symbol: "AMEX:SPY", interval: "1D" });
        const qqq = request.security({ symbol: "NASDAQ:QQQ", interval: "1D" });

        // \`SecurityBar.close\` is a \`Series<Price>\` (indexable, NOT
        // number-coercible), so read \`.current\` for the live scalar before the
        // ratio division.
        plot(spy.close.current / qqq.close.current, { title: "SPY/QQQ" });
    },
});
`;

const Z_LAYERING = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { type WorldPoint, defineIndicator, draw, plot, ta } from "@invinite-org/chartlang-core";

// Two persistent edge arrays, accumulated one \`{ time, price }\` vertex per
// bar — the same per-bar-re-emit idiom as fill-between-band.chart.ts. They
// live at module scope (the drawing's geometry, re-snapshotted into one
// \`draw.fillBetween\` callsite every bar).
const fastEdge: WorldPoint[] = [];
const slowEdge: WorldPoint[] = [];

export default defineIndicator({
    name: "Z-Order Layering",
    apiVersion: 1,
    overlay: true,
    // One ribbon, re-emitted every bar from the same source line, so a single
    // "polylines" slot (fill-between's bucket) is the whole drawing budget.
    maxDrawings: { lines: 0, labels: 0, boxes: 0, polylines: 1, other: 0 },
    compute({ bar, ta, plot, draw }) {
        const fast = ta.ema(bar.close, 12);
        const slow = ta.ema(bar.close, 26);

        // Grow both edges by one vertex per bar — the fast EMA is the band's
        // top, the slow EMA its bottom (same construction as fill-between-band).
        if (Number.isFinite(fast.current) && Number.isFinite(slow.current)) {
            fastEdge.push({ time: bar.time, price: fast.current });
            slowEdge.push({ time: bar.time, price: slow.current });
        }

        // The headline: \`z: -1\` pulls the fill BENEATH the price plot. A
        // \`draw.*\` mark renders above plots by default (its band sits higher),
        // so a negative \`z\` is the only way to put a drawing under a plot —
        // the fixed group stack alone forbids it. Re-emitting from this same
        // source line every bar reuses one drawing handle.
        if (fastEdge.length >= 2) {
            draw.fillBetween(fastEdge, slowEdge, {
                fill: "#3b82f6",
                fillAlpha: 0.2,
                color: "#3b82f6",
                lineWidth: 1,
                z: -1,
            });
        }

        // Declared FIRST, so the default "last plot wins" stack would render
        // the SMA at the BOTTOM. \`z: 1\` overrides that order and lifts it back
        // above the price — that inversion is the whole point: if the SMA were
        // plotted last instead, it would sit on top by default and \`z\` would be
        // doing nothing. Emission order is unchanged by \`z\` (presentation only).
        plot(ta.sma(bar.close, 20), { color: "#ef5350", title: "SMA on top", z: 1 });

        // Declared LAST (default z = 0). The "last plot wins" rule would put it
        // on top, but the SMA's \`z: 1\` keeps it below — while its own z = 0
        // still holds it above the z: -1 band.
        plot(bar.close, { color: "#1e293b", title: "Price" });
    },
});
`;

const WEEKDAY_CLOSE_FILTER = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.
//
// Calendar accessor demo: plot the close only on weekdays (Mon–Fri),
// else NaN, so the line breaks across every weekend. Exercises the
// \`time.*\` calendar accessors — \`time.dayofweek(bar.time)\` (Pine's
// \`1=Sun..7=Sat\` convention) — derived from \`bar.time\` (UTC ms epoch),
// never \`Date\`/\`Intl\` (both forbidden on the author path).
//
// The sibling \`session.isOpen\` / \`input.session\` accessors live in the
// same namespace but need INTRADAY bars to discriminate: this demo's
// daily candles all share one time-of-day, so any session window is
// trivially all-open or all-closed. Those are exercised by the
// conformance scenarios (\`calendarSession\`, \`taSessionVolumeProfile\`),
// not here.

import { defineIndicator, plot, time } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Weekday Close Filter",
    apiVersion: 1,
    overlay: true,
    compute({ bar, time, plot }) {
        const dow = time.dayofweek(bar.time); // 1=Sun .. 7=Sat (Pine convention)
        const isWeekday = dow >= 2 && dow <= 6;
        // A bright, thick line so the weekday segments — and the 2-bar break
        // across every weekend (the NaN gaps) — read clearly on top of the
        // green/red candles, which the plotted close value would otherwise
        // blend into.
        plot(isWeekday ? bar.close : Number.NaN, {
            color: "#f59e0b",
            lineWidth: 2,
            title: "Weekday close",
        });
    },
});
`;

const BGCOLOR_BARCOLOR = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { barcolor, bgcolor, defineIndicator, plot, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Bg + Bar Color",
    apiVersion: 1,
    overlay: true,
    compute({ bar, ta, plot, bgcolor, barcolor }) {
        // \`barcolor\` tints each CANDLE by its own direction — blue on an
        // up-close, orange on a down-close. Deliberately NOT the usual
        // green/red candle colors, so the recolor is plainly visible. The
        // Pine-ergonomic alias replaces the verbose
        // \`plot(NaN, { style: { kind: "bar-color", color } })\` form; the
        // color expression is evaluated every bar, so the tint flips as the
        // condition does, and \`barcolor\` carries no transparency.
        barcolor(bar.close.current > bar.open.current ? "#2962ff" : "#ff6d00");

        // \`bgcolor\` washes the whole PANE BACKGROUND by trend regime: a
        // faint green while price holds above its EMA(50), a faint red
        // below. \`transp\` (0 opaque … 100 fully transparent) keeps the wash
        // subtle so the candles stay readable on top of it.
        const trend = ta.ema(bar.close, 50);
        plot(trend, { color: "#90caf9", title: "EMA(50)" });
        bgcolor(bar.close.current > trend.current ? "#26a69a" : "#ef5350", { transp: 85 });
    },
});
`;

const TICK_SNAPPED_LEVELS = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.
//
// Headline \`math.*\` example: compute a support/resistance band around the
// current close and snap each edge to the symbol's tick grid with
// \`math.roundToMintick(level, syminfo.mintick)\` before drawing it. Unlike
// \`mintick-snapped-entry.chart.ts\` (which PLOTS one snapped target), this
// snaps multiple LEVELS into \`draw.horizontalLine\`s — the namespace's
// chart-aware rounding feeding the drawing layer.

import { defineIndicator, input, math } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Tick-Snapped Levels",
    apiVersion: 1,
    overlay: true,
    inputs: {
        bandPercent: input.float(1.5, { min: 0.1, max: 10, step: 0.1, title: "Band (%)" }),
    },
    compute({ bar, draw, inputs, syminfo }) {
        // Anchor a band around the current close, then snap each edge to the
        // tick grid so the lines land on real, tradable price levels. \`math\` is
        // a module-scope import (not a \`compute\` field); \`syminfo\` is the field
        // supplying the tick size.
        const fraction = (inputs.bandPercent as number) / 100;
        const resistance = math.roundToMintick(bar.close * (1 + fraction), syminfo.mintick);
        const support = math.roundToMintick(bar.close * (1 - fraction), syminfo.mintick);
        draw.horizontalLine(resistance, { color: "#ef4444", lineStyle: "dashed" });
        draw.horizontalLine(support, { color: "#22c55e", lineStyle: "dashed" });
    },
});
`;

const STR_FORMATTED_HUD = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.
//
// Headline \`str.*\` example: a draw.table HUD whose cells are built with the
// string namespace. \`str.tostring(value, "#.##")\` formats each OHLC field to a
// fixed-precision Pine mask (host-independent, no locale) and \`str.format\` /
// \`str.upper\` compose the header — the dynamic text the already-shipped
// draw.table hole consumes, with no new wire primitive and no capability.

import { defineIndicator, str } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Formatted OHLC HUD",
    apiVersion: 1,
    overlay: true,
    compute({ bar, draw }) {
        // \`str\` is a module-scope import (not a \`compute\` field). Round each
        // price to two decimals once, then drop the strings straight into the
        // table cells.
        const price = (value: number): string => str.tostring(value, "#.##");
        draw.table({
            position: "top-right",
            cells: [
                [
                    {
                        text: str.format("{0} · {1}", str.upper(bar.symbol), bar.interval),
                        bgColor: "#0f172a",
                        textColor: "#f8fafc",
                    },
                    {
                        text: price(bar.close),
                        bgColor: "#0f172a",
                        textColor: "#f8fafc",
                        textHalign: "right",
                    },
                ],
                [
                    { text: "O", textColor: "#94a3b8" },
                    { text: price(bar.open), textColor: "#0f172a", textHalign: "right" },
                ],
                [
                    { text: "H", textColor: "#94a3b8" },
                    { text: price(bar.high), textColor: "#22c55e", textHalign: "right" },
                ],
                [
                    { text: "L", textColor: "#94a3b8" },
                    { text: price(bar.low), textColor: "#ef4444", textHalign: "right" },
                ],
            ],
            borderColor: "#94a3b8",
            borderWidth: 1,
        });
    },
});
`;

const MATH_SCALAR_BAND = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.
//
// Comprehensive \`math.*\` example: a direction-aware band around each bar's
// typical price, built entirely from the pure scalar reducers — \`avg\` / \`sum\`
// (variadic skip-NaN), \`clamp\`, \`sign\`, \`roundTo\`, and the \`nz\` guard. It is
// the companion to \`tick-snapped-levels.chart.ts\`, which demonstrates only the
// chart-aware \`roundToMintick\`. \`math\` is a module-scope import (never a
// \`compute\` field); bare \`Math.*\` stays available alongside it.

import { defineIndicator, math, plot } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Scalar Band",
    apiVersion: 1,
    overlay: true,
    compute({ bar, plot }) {
        // The typical price is the variadic skip-NaN mean of the bar's HLC;
        // the raw band span is the (variadic, skip-NaN) high−low range.
        const typical = math.avg(bar.high, bar.low, bar.close);
        const span = math.sum(bar.high - bar.low, 0);

        // Bound the half-width so a freak bar cannot blow the band open, take
        // the candle direction as a sign, and snap the midline to cents — with
        // an \`nz\` guard so a non-finite rounding can never poison the plot.
        const width = math.clamp(span, 0, typical);
        const dir = math.sign(bar.close - bar.open);
        const mid = math.nz(math.roundTo(typical, 0.01), 0);

        plot(mid + dir * width, { color: "#22c55e", title: "Band edge" });
        plot(mid - dir * width, { color: "#ef4444", title: "Band edge (mirror)" });
    },
});
`;

const STR_LABEL_BUILDER = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.
//
// Comprehensive \`str.*\` example: a \`draw.table\` watchlist HUD whose rows are
// sanitized and formatted entirely with the string namespace — \`split\`,
// \`trim\`, \`replace\`, \`substring\`, \`upper\`, \`startsWith\`, \`contains\`, and
// \`repeat\`. It is the companion to \`str-formatted-hud.chart.ts\`, which
// demonstrates only \`tostring\` / \`format\` / \`upper\`. \`str\` is a module-scope
// import (never a \`compute\` field).

import { defineIndicator, input, str } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "String Label Builder",
    apiVersion: 1,
    overlay: true,
    inputs: {
        // \`input.string(defaultValue, opts?)\` — the first arg IS the default;
        // the \`inputs:\`-block key names it and \`compute\` reads \`inputs.tags\`.
        tags: input.string("btc, eth ,#sol", { title: "Watchlist" }),
    },
    compute({ draw, inputs }) {
        // Split the comma-separated watchlist into one sanitized table row per
        // ticker. \`.split(...).map(...)\` is plain JS array work — only stateful
        // \`ta.*\` / \`draw.*\` calls are loop-restricted — so every \`str.*\` step
        // runs freely inside the callback.
        const raw = inputs.tags as string;
        const rows = str.split(raw, ",").map((token) => {
            const tag = str.trim(token); // drop the stray spaces around each token
            const clean = str.replace(tag, "#", ""); // strip a leading hash (first occurrence)
            const code = str.upper(str.substring(clean, 0, 3)); // first three chars, upper-cased
            const flagged = str.startsWith(tag, "#") || str.contains(tag, "btc");
            return [
                { text: code, textColor: flagged ? "#22c55e" : "#0f172a" },
                { text: flagged ? "watch" : "hold", textColor: "#94a3b8" },
            ];
        });

        draw.table({
            position: "top-right",
            cells: [
                [
                    {
                        // \`repeat\` builds a bullet divider sized to the ticker count.
                        text: str.format("WATCHLIST {0}", str.repeat("•", rows.length)),
                        bgColor: "#0f172a",
                        textColor: "#f8fafc",
                    },
                    { text: "", bgColor: "#0f172a" },
                ],
                ...rows,
            ],
            borderColor: "#94a3b8",
            borderWidth: 1,
        });
    },
});
`;

