const TREND_ANGLE_SLOPE = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, draw, plot, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Trend Angle Slope",
    apiVersion: 1,
    overlay: true,
    // One angled trend line (connecting line + arc + angle label), reused
    // across bars.
    maxDrawings: { lines: 1, labels: 0, boxes: 0, polylines: 0, other: 0 },
    compute({ bar, ta, draw, plot }) {
        // Measure the screen-space slope of the EMA(20) over the last 20 bars:
        // one reused draw.trendAngle from bar.point(-20, ema 20 bars ago) to
        // bar.point(0, ema now), which renders the line plus a small arc and a
        // \`\${angle}°\` label at the tail anchor.
        const LOOKBACK = 20;
        const trend = ta.ema(bar.close, LOOKBACK);
        plot(trend, { color: "#26a69a", title: "EMA(20)" });
        if (Number.isFinite(trend[0]) && Number.isFinite(trend[LOOKBACK])) {
            const a = bar.point(-LOOKBACK, trend[LOOKBACK]);
            const b = bar.point(0, trend[0]);
            draw.trendAngle(a, b, { color: "#22c55e", lineWidth: 2 });
        }
    },
});
`;

const SINE_WAVE_CYCLE = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, draw, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Sine Wave Cycle",
    apiVersion: 1,
    overlay: true,
    // One sine projection (draw.sineLine's bucket is \`other\`), reused across
    // bars.
    maxDrawings: { lines: 0, labels: 0, boxes: 0, polylines: 0, other: 1 },
    compute({ bar, ta, draw }) {
        // Fit a sine wave over a fixed 40-bar window: the baseline is the
        // midpoint of the two anchors, the amplitude half their price span, and
        // the half-period the time between them. Anchoring the \`from\` at the
        // window's low and the \`to\` at its high (40 bars apart) re-fits the one
        // reused wave to the recent range each bar; the renderer extends it
        // across the viewport.
        const SPAN = 40;
        const hi = ta.highest(bar.high, SPAN);
        const lo = ta.lowest(bar.low, SPAN);
        if (Number.isFinite(hi[0]) && Number.isFinite(lo[0])) {
            const from = bar.point(-SPAN, lo[0]);
            const to = bar.point(0, hi[0]);
            draw.sineLine(from, to, { color: "#0ea5e9", lineWidth: 2 });
        }
    },
});
`;

const PIVOT_POLYLINE = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, draw, ta } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Pivot Polyline",
    apiVersion: 1,
    overlay: true,
    // One closed polyline, reused across bars.
    maxDrawings: { lines: 0, labels: 0, boxes: 0, polylines: 1, other: 0 },
    compute({ bar, ta, draw }) {
        // A CLOSED polyline (the renderer auto-connects the last anchor back to
        // the first) through three data-derived points: a 40-bar low, a 20-bar
        // high, and the current close. One reused handle, re-built each bar.
        const lo = ta.lowest(bar.low, 40);
        const hi = ta.highest(bar.high, 20);
        if (Number.isFinite(lo[0]) && Number.isFinite(hi[0])) {
            draw.polyline(
                [bar.point(-40, lo[0]), bar.point(-20, hi[0]), bar.point(0, bar.close[0])],
                { color: "#a855f7", lineWidth: 2 },
            );
        }
    },
});
`;

const SWING_PATH = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, draw } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Swing Path",
    apiVersion: 1,
    overlay: true,
    // One open path, reused across bars.
    maxDrawings: { lines: 0, labels: 0, boxes: 0, polylines: 1, other: 0 },
    compute({ bar, draw }) {
        // An OPEN path (no wrap-around close, unlike draw.polyline) tracing the
        // close at five fixed offsets back to the current bar. Guarded on the
        // deepest lookback so it only draws once 40 bars of history exist; one
        // reused handle, re-built each bar.
        if (Number.isFinite(bar.close[40])) {
            draw.path(
                [
                    bar.point(-40, bar.close[40]),
                    bar.point(-30, bar.close[30]),
                    bar.point(-20, bar.close[20]),
                    bar.point(-10, bar.close[10]),
                    bar.point(0, bar.close[0]),
                ],
                { color: "#3b82f6", lineWidth: 2 },
            );
        }
    },
});
`;

