const IDIOM_BOUNDED_LOOP = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, plot } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Idiom · Bounded Loop Window",
    apiVersion: 1,
    overlay: true,
    compute({ bar, plot }) {
        // Idiom: a rolling window via a BOUNDED \`for\` loop over \`bar.close[i]\`
        // (docs/language/series-and-indexing.md § "Lookback is bounded"). The
        // loop bound MUST be a numeric LITERAL and the index an affine lookback,
        // so the compiler proves it bounded — the loop form of an unrolled
        // \`bar.close[0] + … + bar.close[19]\`, sized to exactly 20 slots, never
        // tripping the \`dynamic-series-index\` fallback.
        let sum = 0;
        for (let i = 0; i < 20; i++) {
            sum += bar.close[i];
        }
        const mean = bar.close.length >= 20 ? sum / 20 : Number.NaN;
        plot(mean, { title: "SMA(20) — bounded loop", color: "#26a69a" });
    },
});
`;

const IDIOM_BAR_POINT = `// Copyright (c) 2026 Invinite. Licensed under the MIT License.
// See the LICENSE file in the repo root for full license text.

import { defineIndicator, draw } from "@invinite-org/chartlang-core";

export default defineIndicator({
    name: "Idiom · Bar Point Anchors",
    apiVersion: 1,
    overlay: true,
    // One line, redrawn every bar from the same source line, so a single
    // "lines" slot is the whole drawing budget we need.
    maxDrawings: { lines: 1, labels: 0, boxes: 0, polylines: 0, other: 0 },
    compute({ bar, draw }) {
        // Idiom: \`bar.point(offset, price)\` resolves an integer bar offset to a
        // \`{ time, price }\` WorldPoint at compute time, spanning past and future
        // (docs/language/series-and-indexing.md § "Anchoring drawings by bar
        // offset"). A NEGATIVE literal offset uses the real historical timestamp
        // (and contributes to lookback like \`series[n]\`); a POSITIVE offset
        // extrapolates a future timestamp (\`lastTime + n * spacing\`). One line is
        // re-emitted from this callsite each bar, so it slides with the chart.
        draw.line(bar.point(-20, bar.close), bar.point(20, bar.close), {
            color: "#3b82f6",
            lineWidth: 2,
        });
    },
});
`;

